def dedup_report(rows, key='id'):
    seen = {}
    unique = []
    conflicts = []
    for r in rows:
        k = r[key]
        if k not in seen:
            seen[k] = r
            unique.append(r)
        else:
            if r != seen[k]:
                conflicts.append({'key': k, 'prev': seen[k], 'curr': r})
    return {'unique': unique, 'conflicts': conflicts}
